-- First, let's see exactly how many orphaned vehicles we're about to delete
SELECT COUNT(*) as orphaned_count FROM vehicles v WHERE v.userId NOT IN (SELECT id FROM users);

-- Delete orphaned vehicles
DELETE FROM vehicles WHERE userId NOT IN (SELECT id FROM users);

-- Verify the deletion
SELECT COUNT(*) as remaining_vehicles FROM vehicles;
SELECT COUNT(*) as remaining_orphaned FROM vehicles v WHERE v.userId NOT IN (SELECT id FROM users);

